#include <iostream>

int computePerimeter(int width, int height) {
    return 2 * (width + height);
}

int computeArea(int width, int height) {
    return width * height;
}

void printResults(int perimeter, int area) {
    std::cout << "Perimeter: " << perimeter << "\n";
    std::cout << "Area: " << area << "\n";
}

int main() {
    int width{};
    int height{};
    std::cin >> width >> height;

    int perimeter{ computePerimeter(width, height) };
    int area{ computeArea(width, height) };
    printResults(perimeter, area);

    return 0;
}

