solution_code:
#include <iostream>

int maxOf(int x, int y) {
    return x * (x >= y) + y * (y > x);
}

int minOf(int x, int y) {
    return x * (x <= y) + y * (y < x);
}

int computeTotal(int a, int b, int c) {
    return a + b + c;
}

int computeAverage(int total, int count) {
    return total / count;
}

int computeSpread(int a, int b, int c) {
    int biggest { maxOf(maxOf(a, b), c) };
    int smallest { minOf(minOf(a, b), c) };
    return biggest - smallest;
}

void printStats(int total, int average, int spread) {
    std::cout << "Total: " << total << '\n';
    std::cout << "Average: " << average << '\n';
    std::cout << "Spread: " << spread << '\n';
}

int main() {
    int s1{}, s2{}, s3{};
    std::cin >> s1 >> s2 >> s3;

    int total { computeTotal(s1, s2, s3) };
    int average { computeAverage(total, 3) };
    int spread { computeSpread(s1, s2, s3) };
    printStats(total, average, spread);

    return 0;
}
